section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/devops-lb-kubernetes.json",
  "title": "Kubernetes Load Balancing: Services, Ingress, Probes",
  "type": "object",
  "required": [
    "services",
    "ingress_controller",
    "tls_strategy",
    "probes_present",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "services": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "name",
          "type",
          "ports"
        ]
      }
    },
    "ingress_controller": {
      "enum": [
        "nginx",
        "traefik",
        "aws_alb",
        "gke_l7",
        "azure_appgw",
        "none"
      ]
    },
    "tls_strategy": {
      "enum": [
        "cert_manager",
        "passthrough",
        "manual_secret"
      ]
    },
    "probes_present": {
      "type": "object",
      "required": [
        "liveness",
        "readiness"
      ]
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
